it('should not send notifications if NotificationService is not subscribed', async () => {
  // Create a separate NotificationService not subscribed to the EventBus
  const isolatedNotificationService = new NotificationService();

  const order = await orderService.createOrder({
    userId: 'user-1',
    items: [
      { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
    ],
  });

  await orderService.updateOrderStatus(order.id, 'confirmed');

  // The isolated service has no notifications since it's not subscribed to events
  expect(isolatedNotificationService.getNotificationCount()).toBe(0);
  // But the subscribed one does
  expect(notificationService.getNotificationCount()).toBe(2);
});

